<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Explorer Bots</title>
<style>
  body {
    margin: 0;
    background: #14161c;
    color: #e8e8ec;
    font-family: "Segoe UI", Arial, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 16px;
  }
  h1 { font-size: 20px; margin: 4px 0 10px; font-weight: 600; letter-spacing: .5px; }
  #hud {
    display: flex;
    gap: 24px;
    align-items: center;
    margin-bottom: 12px;
    background: #1e2230;
    border: 1px solid #323850;
    border-radius: 10px;
    padding: 10px 18px;
  }
  .stat { font-size: 15px; }
  .stat b { color: #7fd4ff; font-variant-numeric: tabular-nums; }
  #reset {
    background: #3b6ef0;
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 16px;
    font-size: 14px;
    cursor: pointer;
  }
  #reset:hover { background: #5583f5; }
  #maze {
    background: #0c0e13;
    border: 2px solid #323850;
    border-radius: 6px;
    padding: 6px;
    line-height: 0;
  }
  canvas { display: block; }
  #legend { margin-top: 10px; font-size: 12px; color: #8b90a3; }
</style>
</head>
<body>
<h1>Maze Explorer &mdash; 24 bots discovering the exit</h1>
<div id="hud">
  <div class="stat">Timer: <b id="timer">0</b> ticks</div>
  <div class="stat">Completed: <b id="completed">0</b> / 24</div>
  <button id="reset">Reset</button>
</div>
<div id="maze"><canvas id="cv"></canvas></div>
<div id="legend">Green square = spawn &middot; Gold square = exit &middot; Bots explore with Tremaux/DFS memory only.</div>

<script>
(function () {
  "use strict";

  var ROWS = 21, COLS = 21, NBOTS = 24, CELL = 25;

  // ---------- deterministic PRNG ----------
  function mulberry32(a) {
    a = a >>> 0;
    return function () {
      a |= 0; a = (a + 0x6D2B79F5) | 0;
      var t = Math.imul(a ^ (a >>> 15), 1 | a);
      t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
      return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
    };
  }

  var DIRS = {
    n: { dr: -1, dc: 0, opp: "s" },
    e: { dr: 0, dc: 1, opp: "w" },
    s: { dr: 1, dc: 0, opp: "n" },
    w: { dr: 0, dc: -1, opp: "e" }
  };

  function key(r, c) { return r * COLS + c; }

  // ---------- perfect maze: iterative recursive backtracker ----------
  function genMaze(rng) {
    var walls = [], r, c;
    for (r = 0; r < ROWS; r++) {
      walls[r] = [];
      for (c = 0; c < COLS; c++) walls[r][c] = { n: true, e: true, s: true, w: true };
    }
    var visited = new Uint8Array(ROWS * COLS);
    var stack = [{ r: 0, c: 0 }];
    visited[0] = 1;
    while (stack.length) {
      var cur = stack[stack.length - 1];
      var opts = [];
      for (var d in DIRS) {
        var nr = cur.r + DIRS[d].dr, nc = cur.c + DIRS[d].dc;
        if (nr >= 0 && nr < ROWS && nc >= 0 && nc < COLS && !visited[key(nr, nc)]) {
          opts.push({ d: d, r: nr, c: nc });
        }
      }
      if (!opts.length) { stack.pop(); continue; }
      var pick = opts[Math.floor(rng() * opts.length)];
      walls[cur.r][cur.c][pick.d] = false;
      walls[pick.r][pick.c][DIRS[pick.d].opp] = false;
      visited[key(pick.r, pick.c)] = 1;
      stack.push({ r: pick.r, c: pick.c });
    }
    return walls;
  }

  // ---------- game state ----------
  var game = {};
  window.game = game;

  var mazeWalls, bots, allDone, drawState;

  function shuffledDirs(rng) {
    var a = ["n", "e", "s", "w"];
    for (var i = a.length - 1; i > 0; i--) {
      var j = Math.floor(rng() * (i + 1));
      var t = a[i]; a[i] = a[j]; a[j] = t;
    }
    return a;
  }

  function makeBot(i, seed) {
    var rng = mulberry32((seed ^ Math.imul(i + 1, 2654435761)) >>> 0);
    var hue = Math.round((360 / NBOTS) * i);
    var bot = {
      r: game.spawn.r, c: game.spawn.c,
      dirOrder: shuffledDirs(rng),
      color: "hsl(" + hue + ",85%,60%)",
      visited: new Set([key(game.spawn.r, game.spawn.c)]),
      stack: [],                 // trail of cells to backtrack through
      deadSet: new Set(),
      path: [{ r: game.spawn.r, c: game.spawn.c }],
      deadEnds: [],
      finishTick: null,
      // rendering only:
      drawR: game.spawn.r, drawC: game.spawn.c
    };
    if (bot.r === game.exit.r && bot.c === game.exit.c) bot.finishTick = 0;
    return bot;
  }

  // One exploration step: purely local knowledge (walls of the current cell
  // sensed on arrival + the bot's own visited/dead memory). No global search.
  function stepBot(bot) {
    var w = mazeWalls[bot.r][bot.c];
    var target = null;
    for (var i = 0; i < 4; i++) {
      var d = bot.dirOrder[i];
      if (w[d]) continue;                          // wall sensed locally
      var nr = bot.r + DIRS[d].dr, nc = bot.c + DIRS[d].dc;
      if (bot.visited.has(key(nr, nc))) continue;  // own memory only
      target = { r: nr, c: nc };
      break;
    }
    if (target) {
      bot.stack.push({ r: bot.r, c: bot.c });
      bot.r = target.r; bot.c = target.c;
      bot.visited.add(key(bot.r, bot.c));
    } else {
      // dead end / fully explored branch: mark dead, backtrack one cell
      var k = key(bot.r, bot.c);
      if (!bot.deadSet.has(k)) {
        bot.deadSet.add(k);
        bot.deadEnds.push({ r: bot.r, c: bot.c });
      }
      if (!bot.stack.length) return; // safety (cannot happen in perfect maze)
      var prev = bot.stack.pop();
      bot.r = prev.r; bot.c = prev.c;
    }
    bot.path.push({ r: bot.r, c: bot.c });
    if (bot.r === game.exit.r && bot.c === game.exit.c) {
      bot.finishTick = game.elapsed;
    }
  }

  game.tick = function (n) {
    n = (n === undefined) ? 1 : (n | 0);
    for (var t = 0; t < n; t++) {
      if (allDone) return;
      game.elapsed++;
      var remaining = 0;
      for (var i = 0; i < bots.length; i++) {
        var b = bots[i];
        if (b.finishTick !== null) continue;
        stepBot(b);
        if (b.finishTick === null) remaining++;
      }
      if (remaining === 0) allDone = true; // timer frozen at last arrival
    }
    updateHud();
  };

  game.walls = function (r, c) {
    var w = mazeWalls[r][c];
    return { n: w.n, e: w.e, s: w.s, w: w.w };
  };

  game.reset = function (seed) {
    if (typeof seed !== "number" || !isFinite(seed)) {
      seed = Math.floor(Math.random() * 0x7fffffff);
    }
    seed = seed >>> 0;
    game.seed = seed;
    var rng = mulberry32(seed);
    mazeWalls = genMaze(rng);
    game.size = { rows: ROWS, cols: COLS };
    game.spawn = { r: 0, c: 0 };
    game.exit = { r: ROWS - 1, c: COLS - 1 };
    game.elapsed = 0;
    allDone = false;
    bots = [];
    for (var i = 0; i < NBOTS; i++) bots.push(makeBot(i, seed));
    game.bots = bots;
    allDone = bots.every(function (b) { return b.finishTick !== null; });
    updateHud();
  };

  // ---------- rendering ----------
  var cv = document.getElementById("cv");
  cv.width = COLS * CELL;
  cv.height = ROWS * CELL;
  var ctx = cv.getContext("2d");

  function updateHud() {
    document.getElementById("timer").textContent = game.elapsed;
    var done = 0;
    for (var i = 0; i < bots.length; i++) if (bots[i].finishTick !== null) done++;
    document.getElementById("completed").textContent = done;
  }

  function render() {
    ctx.fillStyle = "#0c0e13";
    ctx.fillRect(0, 0, cv.width, cv.height);

    // spawn / exit markers
    ctx.fillStyle = "rgba(80,220,120,0.35)";
    ctx.fillRect(game.spawn.c * CELL + 3, game.spawn.r * CELL + 3, CELL - 6, CELL - 6);
    ctx.fillStyle = "rgba(255,200,60,0.55)";
    ctx.fillRect(game.exit.c * CELL + 3, game.exit.r * CELL + 3, CELL - 6, CELL - 6);

    // walls
    ctx.strokeStyle = "#a7b0cc";
    ctx.lineWidth = 2;
    ctx.lineCap = "square";
    ctx.beginPath();
    for (var r = 0; r < ROWS; r++) {
      for (var c = 0; c < COLS; c++) {
        var w = mazeWalls[r][c];
        var x = c * CELL, y = r * CELL;
        if (w.n) { ctx.moveTo(x, y); ctx.lineTo(x + CELL, y); }
        if (w.w) { ctx.moveTo(x, y); ctx.lineTo(x, y + CELL); }
        if (r === ROWS - 1 && w.s) { ctx.moveTo(x, y + CELL); ctx.lineTo(x + CELL, y + CELL); }
        if (c === COLS - 1 && w.e) { ctx.moveTo(x + CELL, y); ctx.lineTo(x + CELL, y + CELL); }
      }
    }
    ctx.stroke();

    // bots: smooth interpolation toward their logical cell, centered in corridor
    for (var i = 0; i < bots.length; i++) {
      var b = bots[i];
      b.drawR += (b.r - b.drawR) * 0.22;
      b.drawC += (b.c - b.drawC) * 0.22;
      if (Math.abs(b.drawR - b.r) < 0.004) b.drawR = b.r;
      if (Math.abs(b.drawC - b.c) < 0.004) b.drawC = b.c;
      var cx = (b.drawC + 0.5) * CELL;
      var cy = (b.drawR + 0.5) * CELL;
      // slight orbit offset so stacked bots stay visible
      var ang = (i / NBOTS) * Math.PI * 2;
      cx += Math.cos(ang) * 3.5;
      cy += Math.sin(ang) * 3.5;
      ctx.beginPath();
      ctx.arc(cx, cy, 4.5, 0, Math.PI * 2);
      ctx.fillStyle = b.color;
      ctx.fill();
      ctx.lineWidth = 1;
      ctx.strokeStyle = "rgba(0,0,0,0.5)";
      ctx.stroke();
    }
    requestAnimationFrame(render);
  }

  document.getElementById("reset").addEventListener("click", function () {
    game.reset();
  });

  // auto-run for live viewing; tick() itself is a no-op after the last arrival
  setInterval(function () {
    if (!allDone) game.tick(1);
  }, 110);

  game.reset();
  requestAnimationFrame(render);
})();
</script>
</body>
</html>
